{
  "role": "assistant",
  "content": [
    {
      "type": "text",
      "text": "I need to check the stock price for AAPL."
    },
    {
      "type": "tool_use",
      "id": "toolu_01A12v3xX",
      "name": "get_stock_price",
      "input": { "symbol": "AAPL" }
    }
  ],
  "stop_reason": "tool_use"
}

const tools = [
  {
    name: "get_stock_price",
    description: "Get the current stock price for a given symbol. Use this when you need real-time stock prices.",
    input_schema: {
      type: "object",
      properties: {
        symbol: {
          type: "string",
          description: "Stock symbol (e.g., 'AAPL' for Apple)"
        }
      },
      required: ["symbol"]
    }
  }
];

const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [
    {
      role: "user",
      content: "What's the stock price for AAPL?"
    }
  ],
  tools: tools,
  tool_choice: { type: "auto" } // Default: Claude decides when to call
});

// When stop_reason == "tool_use"
if (response.stop_reason === "tool_use") {
  // Extract tool_use blocks from content
  const toolUseBlock = response.content.find(c => c.type === "tool_use");

  console.log("Tool name:", toolUseBlock.name);
  console.log("Tool input:", toolUseBlock.input);
  console.log("Tool ID:", toolUseBlock.id);

  // Extract: name, input, id
  const toolName = toolUseBlock.name; // "get_stock_price"
  const toolInput = toolUseBlock.input; // { symbol: "AAPL" }
  const toolId = toolUseBlock.id; // "toolu_01A12v3xX"
}

// Your app executes the tool
function executeTool(toolName, toolInput) {
  switch (toolName) {
    case "get_stock_price":
      return getStockPrice(toolInput.symbol);
    case "query_database":
      return queryDatabase(toolInput.query);
    default:
      throw new Error(`Unknown tool: ${toolName}`);
  }
}

// Execute
const result = executeTool(toolName, toolInput);
// Example: result = 175.43

// Create tool_result block
const toolResultBlock = {
  type: "tool_result",
  tool_use_id: toolId, // "toolu_01A12v3xX"
  content: result.toString() // "175.43"
};

// Send back to Claude
const response2 = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [
    ...response.messages,
    {
      role: "user",
      content: [toolResultBlock]
    }
  ],
  tools: tools
});

// Claude continues reasoning with result
console.log(response2.content[0].text);
// "AAPL is currently trading at $175.43"

// Claude requests multiple tools in one turn
const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [
    {
      role: "user",
      content: "What are the stock prices for AAPL and GOOGL?"
    }
